prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?startTask ?startName
  ?endTask ?endName
  (COUNT(DISTINCT ?mid) AS ?numMid)
  (COUNT(DISTINCT ?mid2) AS ?numMid2)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "4fba0078103d44d9846d4fbec51710cb" ;
         tai:belongsTo ?org .

  ?startTask a bboExt:ChoreographyTask ;
             bbo:name ?startName ;
             tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?startName)), LCASE("Wybiera samochód oraz czas najmu")))

  ?endTask a bboExt:ChoreographyTask ;
           bbo:name ?endName ;
           tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?endName)), LCASE("Przygotowuje nową umowe lub zostaje przy poprzedniej")))

  # mids reachable from start
  ?startTask ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?mid .
  ?mid a bboExt:ChoreographyTask ; tai:belongsTo ?choreo .
  FILTER(?mid != ?startTask && ?mid != ?endTask)

  OPTIONAL {
    ?mid2 ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?endTask .
    ?mid2 a bboExt:ChoreographyTask ; tai:belongsTo ?choreo .
    FILTER(?mid2 != ?startTask && ?mid2 != ?endTask)
  }
}
GROUP BY ?startTask ?startName ?endTask ?endName

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?task ?name ?choreo
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "4fba0078103d44d9846d4fbec51710cb" ;
         tai:belongsTo ?org .

  ?task a bboExt:ChoreographyTask ;
        bbo:name ?name ;
        tai:belongsTo ?choreo .
  FILTER(
    CONTAINS(LCASE(STR(?name)), LCASE("Wybiera samochód oraz czas najmu"))
    || CONTAINS(LCASE(STR(?name)), LCASE("Przygotowuje nową umowe lub zostaje przy poprzedniej"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?task
  (COALESCE(?name, STR(?task)) AS ?taskLabel)
  (SAMPLE(?choreo) AS ?choreo)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "4fba0078103d44d9846d4fbec51710cb" ;
         tai:belongsTo ?org .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?name . }
}
GROUP BY ?task ?taskLabel
LIMIT 25

