prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  (COUNT(DISTINCT ?taskBetween) AS ?numTasksBetween)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4fba0078103d44d9846d4fbec51710cb" ;
         tai:belongsTo ?org .

  ?startTask a bboExt:ChoreographyTask ;
             bbo:name "Wybiera samochód oraz czas najmu" ;
             tai:belongsTo ?choreo .

  ?endTask a bboExt:ChoreographyTask ;
           bbo:name "Przygotowuje nową umowe lub zostaje przy poprzedniej" ;
           tai:belongsTo ?choreo .

  ?startTask ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?taskBetween .
  ?taskBetween a bboExt:ChoreographyTask ;
                tai:belongsTo ?choreo .

  ?taskBetween ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?endTask .

  FILTER(?taskBetween != ?startTask)
  FILTER(?taskBetween != ?endTask)
}
